    const parent: number[] = Array(c + 1).fill(0);
    // For each node, keep track of the minimum id in its component
    const minId: number[] = Array(c + 1).fill(0);
    // For each node, keep track of whether it is online
    const online: boolean[] = Array(c + 1).fill(true);

    // DSU find function with path compression
    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    // DSU union function
    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) {
            return false; // already in the same set
