    for (const auto& [u, v] : connections) {
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    // DSU parent array
    vector<long long> parent(c + 1);
    // DSU minId array
    vector<long long> minId(c + 1);
    // Online status array
    vector<bool> online(c + 1, true);

    // Initialize DSU
    for (long long i = 1; i <= c; ++i) {
        parent[i] = i;
        minId[i] = i;
    }

    // DSU find function with path compression
    function<long long(long long)> find = [&](long long u) -> long long {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    };

