        // Union by minId
        if (minId[rootU] < minId[rootV]) {
            parent[rootV] = rootU;
            minId[rootU] = min(minId[rootU], minId[rootV]);
        } else {
            parent[rootU] = rootV;
            minId[rootV] = min(minId[rootV], minId[rootU]);
        }
        return true;
    };

    // Build DSU based on the graph
    for (long long i = 1; i <= c; ++i) {
        for (long long j : graph[i]) {
            if (i < j) {
                union_(i, j);
            }
        }
