function solve(c: number, connections: number[][], queries: number[][]): number[] {
    // Build the graph
    const graph: number[][] = Array.from({ length: c + 1 }, () => []);
    for (const [u, v] of connections) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // For each node, keep track of its parent in the DSU
    const parent: number[] = Array(c + 1).fill(0);
    // For each node, keep track of the minimum id in its component
    const minId: number[] = Array(c + 1).fill(0);
    // For each node, keep track of whether it is online
    const online: boolean[] = Array(c + 1).fill(true);

    // DSU find function with path compression
    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    // DSU union function
    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) {
            return false; // already in the same set
        }
        // Union by rank (here we use minId as a proxy for rank)
        if (minId[rootU] < minId[rootV]) {
            parent[rootV] = rootU;
            minId[rootU] = Math.min(minId[rootU], minId[rootV]);
        } else {
            parent[rootU] = rootV;
            minId[rootV] = Math.min(minId[rootV], minId[rootU]);
        }
        return true;
    }

    // Initialize DSU
    for (let i = 1; i <= c; i++) {
        parent[i] = i;
        minId[i] = i;
    }

    // Process queries
    const result: number[] = [];
    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = find(x);
                // Find the minimum id in the component
                let min = minId[root];
                // Check if there are any online nodes in the component
                let hasOnline = false;
                for (let i = 1; i <= c; i++) {
                    if (online[i] && find(i) === root) {
                        hasOnline = true;
                        min = Math.min(min, i);
                        break;
                    }
                }
                if (hasOnline) {
                    result.push(min);
                } else {
                    result.push(-1);
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}

